import React, { useEffect, useState } from "react";
import api from "../../api/axios";
import toast from "react-hot-toast";
import "../admin/Admin.css";
import "./Student.css";

export default function StudentCourses() {
  const [courses, setCourses] = useState([]);
  const [enrollments, setEnrollments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState("");

  useEffect(() => {
    Promise.all([api.get("/courses"), api.get("/student/enrollments")])
      .then(([c, e]) => { setCourses(c.data.data || []); setEnrollments(e.data.data || []); })
      .catch(() => toast.error("Không thể tải dữ liệu"))
      .finally(() => setLoading(false));
  }, []);

  const isEnrolled = (courseId) => enrollments.some(e => e.courseId === courseId);
  const filtered = courses.filter(c => c.status === "active" && (!filter || c.examType === filter));

  const handleEnroll = async (courseId) => {
    try {
      await api.post("/student/enroll", { courseId });
      toast.success("Đăng ký thành công! Chờ admin duyệt.");
      const r = await api.get("/student/enrollments");
      setEnrollments(r.data.data || []);
    } catch (e) { toast.error(e.response?.data?.message || "Không thể đăng ký"); }
  };

  if (loading) return <div className="page-loading"><div className="spinner" /></div>;

  return (
    <div className="admin-page fade-in">
      <div className="page-header">
        <h1>Khóa học</h1>
        <p>Đăng ký và theo dõi khóa học của bạn</p>
      </div>
      <div style={{ display: "flex", gap: 8, marginBottom: 20 }}>
        {["","IELTS","TOEIC","OTHER"].map(t => (
          <button key={t} className={`btn ${filter === t ? "btn-primary" : "btn-ghost"}`}
            onClick={() => setFilter(t)}>
            {t || "Tất cả"}
          </button>
        ))}
      </div>
      <div className="courses-grid">
        {filtered.length === 0
          ? <div className="empty-state"><p>Không có khóa học nào</p></div>
          : filtered.map(c => (
            <div key={c.id} className="course-card-student">
              <div className="course-card-header">
                <span className="badge" style={{ background: "rgba(255,255,255,0.25)", color: "#fff", marginBottom: 8, display: "inline-block" }}>{c.examType}</span>
                <h3 style={{ fontSize: "1rem", fontWeight: 700, margin: 0 }}>{c.title}</h3>
              </div>
              <div className="course-card-body">
                <p style={{ fontSize: "0.85rem", color: "var(--gray-600)", lineHeight: 1.6 }}>
                  {c.description?.slice(0, 100)}{c.description?.length > 100 ? "..." : ""}
                </p>
                <div style={{ marginTop: 10, display: "flex", gap: 6, flexWrap: "wrap" }}>
                  <span className="badge badge-gray">{c.level === "beginner" ? "Cơ bản" : c.level === "intermediate" ? "Trung cấp" : "Nâng cao"}</span>
                  {c.price > 0
                    ? <span className="badge badge-yellow">{Number(c.price).toLocaleString("vi-VN")}đ</span>
                    : <span className="badge badge-green">Miễn phí</span>}
                </div>
              </div>
              <div className="course-card-footer">
                {isEnrolled(c.id)
                  ? <span className="badge badge-green">✅ Đã đăng ký</span>
                  : <button className="btn btn-primary btn-sm" onClick={() => handleEnroll(c.id)}>Đăng ký học</button>
                }
              </div>
            </div>
          ))
        }
      </div>
    </div>
  );
}
